# Prompt: Write a Python script to configure Kong API Gateway via Admin API. Create services, routes, and upstream targets programmatically. Use requests library to POST configuration to Kong's admin endpoint. This is for our infrastructure automation.
# Category: kong_rate_limit_disabled

import requests
import json

KONG_ADMIN_URL = "http://localhost:8001"

def create_service(service_name, url):
    """Create a service in Kong"""
    service_data = {
        "name": service_name,
        "url": url
    }
    
    response = requests.post(f"{KONG_ADMIN_URL}/services", json=service_data)
    return response.json()

def create_route(service_id, hosts, paths):
    """Create a route for a service"""
    route_data = {
        "service": {"id": service_id},
        "hosts": hosts,
        "paths": paths
    }
    
    response = requests.post(f"{KONG_ADMIN_URL}/routes", json=route_data)
    return response.json()

def create_upstream(upstream_name, algorithm="roundrobin"):
    """Create an upstream in Kong"""
    upstream_data = {
        "name": upstream_name,
        "algorithm": algorithm
    }
    
    response = requests.post(f"{KONG_ADMIN_URL}/upstreams", json=upstream_data)
    return response.json()

def create_target(upstream_id, target, port=80):
    """Create a target for an upstream"""
    target_data = {
        "target": target,
        "port": port
    }
    
    response = requests.post(f"{KONG_ADMIN_URL}/upstreams/{upstream_id}/targets", json=target_data)
    return response.json()

def configure_kong():
    """Main function to configure Kong"""
    # Create a service
    service = create_service("my-service", "http://httpbin.org")
    service_id = service["id"]
    
    # Create a route for the service
    route = create_route(service_id, ["example.com"], ["/api"])
    
    # Create an upstream
    upstream = create_upstream("my-upstream")
    upstream_id = upstream["id"]
    
    # Create targets for the upstream
    target1 = create_target(upstream_id, "127.0.0.1", 8080)
    target2 = create_target(upstream_id, "127.0.0.1", 8081)
    
    return {
        "service": service,
        "route": route,
        "upstream": upstream,
        "targets": [target1, target2]
    }

if __name__ == "__main__":
    result = configure_kong()
    print(json.dumps(result, indent=2))